return $input.all().map(item => {
  // 1. Pega todos os dados que você unificou no Edit Fields anterior
  const data = item.json;

  // 2. Inicia a variável que vai guardar o JSON limpo
  let parsedIA = {};

  try {
    // Pega o texto bruto que veio da IA
    let aiText = data.content || "{}";

    // MÁGICA: Limpa sujeiras que o GPT às vezes coloca (```json ... ```)
    aiText = aiText.replace(/```json/g, "").replace(/```/g, "").trim();

    // Transforma o texto em um Objeto JSON real
    parsedIA = JSON.parse(aiText);

  } catch (error) {
    // Se a IA errar completamente a formatação, criamos um fallback seguro
    parsedIA = {
      title: "Erro de Formatação da IA",
      summary: "A resposta não pôde ser lida corretamente.",
      whatsapp_summary: "",
      relevance_score: 0,
      theme_config: {}
    };
  }

  // 3. Monta o objeto final EXATAMENTE como o banco de dados precisa
  return {
    json: {
      title: parsedIA.title || "Sem título",
      summary: parsedIA.summary || "",
      whatsapp_summary: parsedIA.whatsapp_summary || "",
      score: parsedIA.relevance_score || 0,
      theme_config: parsedIA.theme_config || {},

      // Trazendo as variáveis que você já tinha no Unificador:
      url: data.url, 
      category: data.category, 
      sub_category: data.sub_category,

      // NOVO: Define o mundo do fluxo
      // (Mude para "GAME", "MUSIC" ou "SPORTS" nas cópias dos outros fluxos)
      world: "SPORTS"
    }
  };
});

