let text = '';
try {
  text = $input.all()[0].json.output[0].content[0].text;
} catch (e) {
  text = $json.text || $json.content || '';
}

if (text.includes('ERRO_DE_TIMEOUT_IGNORAR')) return { json: { noticias: [] } };

let parsed = [];
try {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    parsed = JSON.parse(text);
  }
} catch (e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) {
    const obj = JSON.parse(m[0]);
    parsed = obj.articles || obj.headlines || obj.noticias || [];
  }
}

// 💥 BUGFIX: Filtra links inválidos, indefinidos ou vazios, e garante a chave 'link'
let validNews = parsed.filter(n => {
  const url = String(n.link || n.url || '').trim();
  return url.startsWith('http') && url !== 'undefined' && url !== 'null';
});
validNews = validNews.map(n => ({ ...n, link: (n.link || n.url).trim() }));

return { json: { noticias: validNews } };

