let is_duplicate = false;
let is_recent = true;
let original_date = new Date().toISOString();
try {
  const content = $input.all()[0].json.output[0].content[0].text;
  // Limpa formatação markdown se houver
  const cleanedContent = content.replace(/```json/g, "").replace(/```/g, "").trim();
  const parsed = JSON.parse(cleanedContent);
  if (parsed.is_duplicate !== undefined) is_duplicate = parsed.is_duplicate;
  if (parsed.is_recent !== undefined) is_recent = parsed.is_recent;
  if (parsed.original_date) original_date = parsed.original_date;
} catch (e) {}

const original = $('IF: URL Inédita?').item.json;
return { json: { ...original, is_duplicate: is_duplicate, is_recent: is_recent, original_date: original_date } };
